select tb.*, (select r.id from jsh_user_business ub left join jsh_role r on ub.value=concat('[',r.id,']') and COALESCE(r.delete_flag,'0') !='1' where ub.type='UserRole' and ub.key_id=cast(tb.id as varchar) LIMIT 1) roleId, (select r."name" from jsh_user_business ub left join jsh_role r on ub.value=concat('[',r.id,']') and COALESCE(r.delete_flag,'0') !='1' where ub.type='UserRole' and ub.key_id=cast(tb.id as varchar) LIMIT 1) roleName from ( select u.id, u.username, u.login_name, u.position, u.leader_flag, u.email, u.phonenum, u.description, u.remark,u.isystem,org.id as orgaId,u.tenant_id,u.status,org.org_abr, rel.user_blng_orga_dspl_seq,rel.id as orgaUserRelId FROM jsh_user u left join jsh_orga_user_rel rel on u.id=rel.user_id and COALESCE(rel.delete_flag,'0') !='1' left join jsh_organization org on rel.orga_id=org.id and COALESCE(org.delete_flag,'0') !='1' where 1=1 and COALESCE(u.delete_flag,'0') !='1'
and u.username like #{bindUserName}
and u.login_name like #{bindLoginName}
order by rel.user_blng_orga_dspl_seq,u.id desc ) tb

select count(u.id)
FROM jsh_user u
where 1=1
and COALESCE(u.delete_flag,'0') !='1'


    and u.username like #{bindUserName}



    and u.login_name like #{bindLoginName}

select u.id, u.username, u.login_name, u.position, u.email, u.phonenum, u.description, u.remark,u.isystem FROM jsh_user u where 1=1 and u.status = 0 and COALESCE(u.delete_flag,'0') !='1'
and u.userName = #{userName}
and u.login_name = #{loginName}
order by u.id desc

